// src/pages/HomeScreen.js
import React, { useMemo, useState } from "react";
import {
  SafeAreaView,
  View,
  Text,
  StyleSheet,
  Image,
  TextInput,
  TouchableOpacity,
  Platform,
  useWindowDimensions,
} from "react-native";

const nalicoreLogo = require("../../assets/nalicore_logo.png");

export default function HomeScreen() {
  const { width } = useWindowDimensions();

  const isSmall = width < 420;
  const isDesktop = width >= 1024;

  const containerMaxWidth = isDesktop ? 600 : 560;

  const [query, setQuery] = useState("Total borne 10 entre\nenfant noir chez le boss");

  const resolved = useMemo(
    () => ({
      quartier: "Odza",
      secteur: "Borne 10",
      sousSecteur: "Total borne 10",
      entree: "Enfant Noir",
      lieu: "Chez le Boss",
      banoc: "Q5TCL",
      latitude: 3.7862,
      longitude: 111.53045,
    }),
    []
  );

  const onResolve = () => console.log("Resolve:", query);
  const onNavigate = () =>
    console.log("Navigate:", resolved.latitude, resolved.longitude);

  return (
    <SafeAreaView style={styles.safe}>
      {/* soft vignette background like the mockup */}
      <View style={styles.bg}>
        <View style={styles.glowTL} />
        <View style={styles.glowTR} />
        <View style={styles.glowBL} />

        <View style={[styles.shell, { maxWidth: containerMaxWidth }]}>
          {/* HEADER */}
          <View style={styles.headerRow}>
            <Image
              source={nalicoreLogo}
              style={[styles.logo, { width: isSmall ? 210 : 250 }]}
              resizeMode="contain"
            />
            <Text
              style={[
                styles.tagline,
                { fontSize: isSmall ? 15 : 16, lineHeight: isSmall ? 20 : 22 },
              ]}
              numberOfLines={2}
            >
              Natural Address{"\n"}Location Infrastructure
            </Text>
          </View>

          {/* SEARCH */}
          <View style={styles.searchBar}>
            <View style={styles.searchLeft}>
              <Magnifier />
              <TextInput
                value={query}
                onChangeText={setQuery}
                style={[
                  styles.searchInput,
                  { fontSize: isSmall ? 17 : 18, lineHeight: isSmall ? 22 : 24 },
                ]}
                placeholder="Type an address…"
                placeholderTextColor="rgba(31,42,68,0.40)"
                multiline
                numberOfLines={2}
                scrollEnabled={false}
                textAlignVertical="center"
                underlineColorAndroid="transparent"
              />
            </View>

            <View style={styles.searchDivider} />

            {/* Resolve button: rectangle, only right corners rounded (like mockup) */}
            <TouchableOpacity
              activeOpacity={0.92}
              style={styles.resolveBtn}
              onPress={onResolve}
            >
              <Text style={[styles.resolveText, { fontSize: isSmall ? 18 : 19 }]}>
                Resolve
              </Text>
            </TouchableOpacity>
          </View>

          {/* RESOLVED CARD */}
          <View style={styles.card}>
            <View style={styles.cardHeader}>
              <Text style={[styles.cardTitle, { fontSize: isSmall ? 26 : 28 }]}>
                Resolved Address
              </Text>
            </View>

            <View style={styles.cardBody}>
              <Row label="Quartier:" value={resolved.quartier} isSmall={isSmall} />
              <Row label="Secteur:" value={resolved.secteur} isSmall={isSmall} />
              <Row label="Sous-secteur:" value={resolved.sousSecteur} isSmall={isSmall} />
              <Row label="Entrée:" value={resolved.entree} isSmall={isSmall} />
              <Row label="Lieu:" value={resolved.lieu} isSmall={isSmall} />

              <View style={styles.row}>
                <Text style={[styles.label, { fontSize: isSmall ? 15 : 16 }]}>
                  BANOC:
                </Text>
                <View style={styles.banocPill}>
                  <Text style={styles.banocText}>{resolved.banoc}</Text>
                </View>
              </View>

              {/* ✅ GPS removed (as you asked) */}
              <Row
                label="Latitude:"
                value={Number(resolved.latitude).toFixed(5)}
                isSmall={isSmall}
              />
              <Row
                label="Longitude:"
                value={Number(resolved.longitude).toFixed(5)}
                isSmall={isSmall}
              />

              <TouchableOpacity activeOpacity={0.92} style={styles.navBtn} onPress={onNavigate}>
                <View style={styles.navIconBubble}>
                  <PinIcon />
                </View>
                <Text style={[styles.navText, { fontSize: isSmall ? 20 : 21 }]}>
                  Navigate to Location
                </Text>
              </TouchableOpacity>
            </View>
          </View>
        </View>
      </View>
    </SafeAreaView>
  );
}

function Row({ label, value, isSmall }) {
  return (
    <View style={styles.row}>
      <Text style={[styles.label, { fontSize: isSmall ? 15 : 16 }]}>{label}</Text>
      <Text style={[styles.value, { fontSize: isSmall ? 18 : 19 }]} numberOfLines={1}>
        {value}
      </Text>
    </View>
  );
}

/** Simple magnifier that matches the mockup vibe */
function Magnifier() {
  return (
    <View style={styles.magWrap}>
      <View style={styles.magCircle} />
      <View style={styles.magHandle} />
    </View>
  );
}

function PinIcon() {
  return (
    <View style={styles.pin}>
      <View style={styles.pinHead} />
      <View style={styles.pinStem} />
    </View>
  );
}

const styles = StyleSheet.create({
  safe: { flex: 1, backgroundColor: "#E9ECF6" },

  bg: {
    flex: 1,
    alignItems: "center",
    justifyContent: "flex-start",
    paddingHorizontal: 18,
    paddingTop: 18,
  },

  // background glow blobs (imitates the mockup gradient/vignette)
  glowTL: {
    position: "absolute",
    left: -120,
    top: -140,
    width: 360,
    height: 360,
    borderRadius: 180,
    backgroundColor: "rgba(128, 96, 255, 0.20)",
  },
  glowTR: {
    position: "absolute",
    right: -120,
    top: -160,
    width: 380,
    height: 380,
    borderRadius: 190,
    backgroundColor: "rgba(96, 140, 255, 0.18)",
  },
  glowBL: {
    position: "absolute",
    left: -140,
    bottom: -220,
    width: 420,
